import{_ as t,c as r}from"./app.e53bf642.js";const n={},o=r('<h1 id="\u9644\u5F55-3" tabindex="-1"><a class="header-anchor" href="#\u9644\u5F55-3" aria-hidden="true">#</a> \u9644\u5F55 3</h1><h2 id="\u672F\u8BED\u8868" tabindex="-1"><a class="header-anchor" href="#\u672F\u8BED\u8868" aria-hidden="true">#</a> \u672F\u8BED\u8868</h2><h3 id="\u9996\u5B57\u6BCD\u7F29\u7565\u8BCD" tabindex="-1"><a class="header-anchor" href="#\u9996\u5B57\u6BCD\u7F29\u7565\u8BCD" aria-hidden="true">#</a> \u9996\u5B57\u6BCD\u7F29\u7565\u8BCD</h3><table><thead><tr><th>\u7F29\u7565\u8BCD</th><th>\u89E3\u91CA</th></tr></thead><tbody><tr><td>ATDD</td><td>\u9A8C\u6536\u6D4B\u8BD5\u9A71\u52A8\u5F00\u53D1</td></tr><tr><td>BDD</td><td>\u884C\u4E3A\u9A71\u52A8\u5F00\u53D1</td></tr><tr><td>BRD</td><td>\u4E1A\u52A1\u9700\u6C42\u6587\u6863</td></tr><tr><td>DA</td><td>\u89C4\u8303\u654F\u6377</td></tr><tr><td>DoD</td><td>\u5B8C\u6210\u7684\u5B9A\u4E49</td></tr><tr><td>DoR</td><td>\u51C6\u5907\u5C31\u7EEA\u7684\u5B9A\u4E49</td></tr><tr><td>DSDM</td><td>\u52A8\u6001\u7CFB\u7EDF\u5F00\u53D1\u65B9\u6CD5</td></tr><tr><td>EVO</td><td>\u6E10\u8FDB\u4EF7\u503C\u4EA4\u4ED8</td></tr><tr><td>LeSS</td><td>\u5927\u89C4\u6A21\u654F\u6377\u5F00\u53D1</td></tr><tr><td>LSD</td><td>\u7CBE\u76CA\u8F6F\u4EF6\u5F00\u53D1</td></tr><tr><td>PDCA</td><td>\u8BA1\u5212 - \u5B9E\u65BD - \u68C0\u67E5 - \u884C\u52A8</td></tr><tr><td>PMO</td><td>\u9879\u76EE\u7BA1\u7406\u529E\u516C\u5BA4</td></tr><tr><td>ROI</td><td>\u6295\u8D44\u56DE\u62A5\u7387</td></tr><tr><td>RUP</td><td>\u7EDF\u4E00\u8F6F\u4EF6\u5F00\u53D1\u8FC7\u7A0B</td></tr><tr><td>SAFe</td><td>\u5927\u89C4\u6A21\u654F\u6377\u6846\u67B6</td></tr><tr><td>SBE</td><td>\u5B9E\u4F8B\u5316\u9700\u6C42</td></tr><tr><td>XP</td><td>\u6781\u9650\u7F16\u7A0B</td></tr></tbody></table><h3 id="\u5B9A\u4E49" tabindex="-1"><a class="header-anchor" href="#\u5B9A\u4E49" aria-hidden="true">#</a> \u5B9A\u4E49</h3><p><strong>A3. A3</strong> \u4E00\u79CD\u601D\u7EF4\u65B9\u5F0F\u53CA\u4E00\u79CD\u89E3\u51B3\u95EE\u9898\u7684\u7CFB\u7EDF\u5316\u8FC7\u7A0B\uFF0C\u5C06\u76F8\u5173\u4FE1\u606F\u56CA\u62EC\u5728\u4E00\u5F20 A3 \u5927\u5C0F\u7684\u7EB8\u4E0A\u3002</p><p><strong>Acceptance Test-Driven Development(ATDD). \u9A8C\u6536\u6D4B\u8BD5\u9A71\u52A8\u5F00\u53D1</strong> \u4E00\u79CD\u534F\u4F5C\u5236\u5B9A\u9A8C\u6536\u6D4B\u8BD5\u6807\u51C6\u7684\u65B9\u6CD5\u7528\u4E8E\u521B\u5EFA\u4EA4\u4ED8\u524D\u7684\u9A8C\u6536\u6D4B\u8BD5\u3002</p><p><strong>Agile. \u654F\u6377</strong> \u7528\u4E8E\u63CF\u8FF0\u53CD\u6620\u4E86\u300A\u654F\u6377\u5BA3\u8A00\u300B\u6240\u8FF0\u4EF7\u503C\u89C2\u548C\u539F\u5219\u7684\u601D\u7EF4\u6A21\u5F0F\u7684\u4E00\u4E2A\u672F\u8BED\u3002</p><p><strong>Agile Coach. \u654F\u6377\u6559\u7EC3</strong> \u6307\u638C\u63E1\u4E86\u654F\u6377\u503C\u4F3C\u4E4E\u548C\u7ECF\u9A8C\u7684\u4EBA\u5458\uFF0C\u5728\u5176\u7EC4\u7EC7\u548C\u56E2\u961F\u8F6C\u578B\u4E2D\u80FD\u591F\u53D1\u6325\u57F9\u8BAD\u3001\u8F85\u5BFC\u548C\u6307\u5BFC\u7684\u4F5C\u7528\u3002</p><p><strong>Agile Life Cycle. \u654F\u6377\u751F\u547D\u5468\u671F</strong> \u4E00\u79CD\u8FED\u4EE3\u517C\u589E\u91CF\u65B9\u6CD5\u7528\u4E8E\u4F18\u5316\u5DE5\u4F5C\u9879\u76EE\u589E\u52A0\u4EA4\u4ED8\u9891\u7387\u3002</p><p><strong>Agile Manifesto. \u654F\u6377\u5BA3\u8A00</strong> \u654F\u6377\u4EF7\u503C\u89C2\u548C\u539F\u5219\u7684\u6700\u521D\u5B98\u65B9\u5B9A\u4E49\u3002</p><p><strong>Agile Mindset. \u654F\u6377\u601D\u7EF4\u6A21\u5F0F</strong> \u4E00\u79CD\u601D\u7EF4\u548C\u884C\u4E3A\u65B9\u5F0F\uFF0C\u690D\u6839\u4E8E\u300A\u654F\u6377\u5BA3\u8A00\u300B\u7684\u56DB\u5927\u4EF7\u503C\u89C2\u548C\u5341\u4E8C\u6761\u539F\u5219\u3002</p><p><strong>Agile Practitioner. \u654F\u6377\u5B9E\u8DF5\u8005</strong> \u63A5\u53D7\u654F\u6377\u601D\u7EF4\u6A21\u5F0F\uFF0C\u5728\u8DE8\u804C\u80FD\u56E2\u961F\u4E2D\u4E0E\u5FD7\u540C\u9053\u5408\u7684\u540C\u4E8B\u5F00\u5C55\u534F\u4F5C\u7684\u4EBA\u3002\u4E5F\u6210\u4E3A\u654F\u6377\u4E13\u5BB6\u3002</p><p><strong>Agile Principles. \u654F\u6377\u539F\u5219</strong> \u300A\u654F\u6377\u5BA3\u8A00\u300B\u4E2D\u6240\u4F53\u73B0\u7684\u654F\u6377\u9879\u76EE\u4EA4\u4ED8\u7684\u5341\u4E8C\u6761\u539F\u5219\u3002</p><p><strong>Agile Unified Process. \u654F\u6377\u7EDF\u4E00\u8FC7\u7A0B</strong> \u5728\u4E1A\u52A1\u5E94\u7528\u8F6F\u4EF6\u5F00\u53D1\u4E2D\u5E94\u7528\u654F\u6377\u6280\u672F\u548C\u601D\u60F3\u7684\u4E00\u79CD\u7B80\u5355\u4E14\u4FBF\u4E8E\u7406\u89E3\u7684\u65B9\u6CD5\u3002\u5B83\u662F\u7EDF\u4E00\u8F6F\u4EF6\u5F00\u53D1\u8FC7\u7A0B\uFF08RUP\uFF09\u7684\u7B80\u5316\u7248\u672C\u3002</p><p><strong>Agilist. \u654F\u6377\u4E13\u5BB6</strong></p><p><strong>Anti-Pattern. \u53CD\u6A21\u5F0F</strong> \u4E00\u79CD\u5DF2\u77E5\u7684\u3001\u6709\u7F3A\u9677\u7684\u3001\u4E0D\u53EF\u53D6\u7684\u5DE5\u4F5C\u6A21\u5F0F\u3002</p><p><strong>Automated Code Quality Analysis. \u81EA\u52A8\u5316\u4EE3\u7801\u8D28\u91CF\u5206\u6790</strong> \u7528\u4E8E\u68C0\u6D4B\u4EE3\u7801\u5E93\u7F3A\u9677\u548C\u6F0F\u6D1E\u7684\u811A\u672C\u5316\u6D4B\u8BD5\u3002</p><p><strong>Backlog. \u5F85\u529E\u4E8B\u9879\u5217\u8868</strong></p><p><strong>Backlog Refinement. \u5F85\u529E\u4E8B\u9879\u5217\u8868\u7684\u7EC6\u5316</strong> \u5BF9\u9879\u76EE\u9700\u6C42\u548C/\u6216\u6B63\u5728\u8FDB\u884C\u7684\u6D3B\u52A8\u7684\u6E10\u8FDB\u660E\u7EC6\u5176\u4E2D\u56E2\u961F\u534F\u4F5C\u53C2\u4E0E\u9700\u6C42\u7684\u5BA1\u6838\u3001\u66F4\u65B0\u548C\u64B0\u5199\u4EE5\u6EE1\u8DB3\u5BA2\u6237\u9700\u6C42\u3002</p><p><strong>Behavior-Driven Development(BDD). \u884C\u4E3A\u9A71\u52A8\u5F00\u53D1</strong> \u4E00\u79CD\u7CFB\u7EDF\u8BBE\u8BA1\u548C\u786E\u8BA4\u5B9E\u8DF5\u91C7\u7528\u6D4B\u8BD5\u4F18\u5148\u7684\u539F\u5219\u548C\u7C7B\u4F3C\u82F1\u8BED\u7684\u811A\u672C\u3002</p><p><strong>Blended Agile. \u6DF7\u5408\u654F\u6377</strong> \u6307\u540C\u65F6\u4F7F\u7528\u4E24\u79CD\u6216\u4E24\u79CD\u4EE5\u4E0A\u7684\u654F\u6377\u6846\u67B6\u3001\u65B9\u6CD5\u3001\u8981\u7D20\u6216\u5B9E\u8DF5\uFF0C\u4F8B\u5982 Scrum \u4E0E\u6781\u9650\u7F16\u7A0B\u548C\u770B\u677F\u7684\u7ED3\u5408\u4F7F\u7528</p><p><strong>Blocker. \u963B\u788D</strong></p><p><strong>Broken Comb. \u201C\u7834\u68B3\u9F7F\u201D\u4EBA\u624D</strong> \u6307\u5BF9\u56E2\u961F\u6240\u9700\u7684\u591A\u79CD\u6280\u80FD\u638C\u63E1\u7A0B\u5EA6\u6DF1\u6D45\u4E0D\u4E00\u7684\u4EBA\u3002\u4E5F\u79F0\u4E3A\u201D\u989C\u6599\u6EF4\u6D12\u201C\u4EBA\u624D\u3002</p><p><strong>Burndown Chart. \u71C3\u5C3D\u56FE</strong> \u5269\u4F59\u5DE5\u4F5C\u4E0E\u65F6\u95F4\u76D2\u5185\u5269\u4F59\u5B9E\u8DF5\u5173\u7CFB\u7684\u4E00\u79CD\u56FE\u5F62\u5316\u8868\u793A\u5F62\u5F0F\u3002</p><p><strong>Burnup Chart. \u71C3\u8D77\u56FE</strong> \u5BF9\u5DF2\u5B8C\u6210\u5DE5\u4F5C\u4E0E\u4EA7\u54C1\u53D1\u5E03\u5173\u7CFB\u7684\u4E00\u79CD\u56FE\u5F62\u5316\u8868\u793A\u5F62\u5F0F\u3002</p><p><strong>Business Requirement Documents(BRD). \u4E1A\u52A1\u9700\u6C42\u6587\u6863</strong> \u67D0\u7279\u5B9A\u9879\u76EE\u7684\u6240\u6709\u9700\u6C42\u5217\u8868\u3002</p><p><strong>Cadence. \u8282\u594F</strong> \u9879\u76EE\u6267\u884C\u8282\u594F\u3002</p><p><strong>Collective Code Ownership. \u4EE3\u7801\u96C6\u4F53\u6240\u6709</strong> \u4E00\u79CD\u9879\u76EE\u52A0\u901F\u548C\u534F\u4F5C\u6280\u672F\uFF0C\u4EFB\u4F55\u56E2\u961F\u6210\u5458\u90FD\u6709\u6743\u4FEE\u6539\u4EFB\u4F55\u9879\u76EE\u5DE5\u4F5C\u4EA7\u54C1\u6216\u53EF\u4EA4\u4ED8\u6210\u679C\u3002\u5B83\u5F3A\u8C03\u6574\u4E2A\u56E2\u961F\u7684\u8D23\u4EFB\u548C\u6700\u7EC8\u8D23\u4EFB\u3002</p><p><strong>Continuous Delivery. \u6301\u7EED\u4EA4\u4ED8</strong> \u7ACB\u5373\u5411\u5BA2\u6237\u4EA4\u4ED8\u529F\u80FD\u589E\u91CF\u7684\u5B9E\u8DF5\u5F80\u5F80\u901A\u8FC7\u91C7\u7528\u5C0F\u6279\u91CF\u5DE5\u4F5C\u548C\u81EA\u52A8\u5316\u6280\u672F\u5B9E\u73B0\u3002</p><p><strong>Continuous Integration. \u6301\u7EED\u6574\u5408</strong> \u4E00\u79CD\u56E2\u961F\u5404\u6210\u5458\u7684\u5DE5\u4F5C\u4EA7\u54C1\u7ECF\u5E38\u6574\u5408\u5E76\u5F7C\u6B64\u786E\u8BA4\u7684\u5B9E\u8DF5\u3002</p><p><strong>Cross-Functional Team. \u8DE8\u804C\u80FD\u56E2\u961F</strong> \u6307\u7531\u5B9E\u8DF5\u8005\u7EC4\u6210\u7684\u56E2\u961F\uFF0C\u8FD9\u4E9B\u5B9E\u8DF5\u8005\u638C\u63E1\u4EA4\u4ED8\u6709\u4EF7\u503C\u4EA7\u54C1\u589E\u91CF\u6240\u9700\u7684\u5404\u79CD\u6280\u80FD\u3002</p><p><strong>Crystal Family of Methodologies. \u6C34\u6676\u5BB6\u65CF\u65B9\u6CD5\u8BBA</strong> \u8F7B\u91CF\u7EA7\u654F\u6377\u8F6F\u4EF6\u5F00\u53D1\u65B9\u6CD5\u7684\u96C6\u5408\uFF0C\u91CD\u70B9\u5173\u6CE8\u7279\u5B9A\u60C5\u51B5\u7684\u9002\u5E94\u6027\u3002</p><p><strong>Daily Scrum. \u6BCF\u65E5\u4F8B\u4F1A</strong> \u6307\u6BCF\u5929\u53EC\u96C6\u7684\u4E00\u79CD\u7B80\u77ED\u7684\u534F\u4F5C\u4F1A\u8BAE\uFF0C\u56E2\u961F\u5C06\u56DE\u987E\u524D\u4E00\u5929\u7684\u8FDB\u5C55\uFF0C\u5BA3\u5E03\u5F53\u5929\u7684\u8BA1\u5212\uFF0C\u5F3A\u8C03\u66FE\u9047\u5230\u6216\u9884\u671F\u51FA\u73B0\u7684\u969C\u788D\u3002\u4E5F\u79F0\u4E3A\u6BCF\u65E5\u7AD9\u4F1A\u3002</p><p><strong>Definition of Done(DoD). \u5B8C\u6210\u7684\u5B9A\u4E49</strong> \u56E2\u961F\u9700\u8981\u6EE1\u8DB3\u7684\u6240\u6709\u6807\u51C6\u7684\u6838\u5BF9\u5355\uFF0C\u53EA\u6709\u53EF\u4EA4\u4ED8\u6210\u679C\u6EE1\u8DB3\u8BE5\u6838\u5BF9\u5355\u624D\u80FD\u662F\u4E3A\u51C6\u5907\u5C31\u7EEA\u53EF\u4F9B\u5BA2\u6237\u4F7F\u7528\u3002</p><p><strong>Definition of Ready(DoR). \u51C6\u5907\u5C31\u7EEA\u7684\u5B9A\u4E49</strong> \u56E2\u961F\u4EE5\u7528\u6237\u9700\u6C42\u4E3A\u4E2D\u5FC3\u7684\u6838\u5BF9\u5355\uFF0C\u5305\u62EC\u56E2\u961F\u5F00\u59CB\u5DE5\u4F5C\u6240\u9700\u7684\u5168\u90E8\u4FE1\u606F\u3002</p><p><strong>DevOps. DevOps</strong> \u901A\u8FC7\u6539\u5584\u5F00\u53D1\u548C\u8FD0\u8425\u5458\u5DE5\u4E4B\u95F4\u7684\u534F\u4F5C\u6765\u7406\u987A\u4EA4\u4ED8\u6D41\u7A0B\u7684\u5404\u79CD\u5B9E\u8DF5\u7684\u96C6\u5408\u3002</p><p><strong>Disciplined Agile (DA). \u89C4\u8303\u654F\u6377</strong> \u6307\u4E00\u79CD\u8FC7\u7A0B\u51B3\u7B56\u6846\u67B6\uFF0C\u80FD\u591F\u56F4\u7ED5\u589E\u91CF\u548C\u8FED\u4EE3\u89E3\u51B3\u65B9\u6848\u7684\u4EA4\u4ED8\u6765\u7B80\u5316\u8FC7\u7A0B\u51B3\u7B56\u3002</p><p><strong>Double-Loop Learning. \u53CC\u5FAA\u73AF\u5B66\u4E60</strong> \u4E00\u79CD\u8D28\u7591\u6F5C\u5728\u7684\u4EF7\u503C\u548C\u5047\u8BBE\u7684\u8FC7\u7A0B\uFF0C\u76EE\u7684\u4E0D\u662F\u4EC5\u5173\u6CE8\u5F81\u5146\uFF0C\u800C\u662F\u4E3A\u4E86\u66F4\u597D\u5730\u9610\u8FF0\u6839\u672C\u539F\u56E0\uFF0C\u5236\u5B9A\u6539\u5584\u5BF9\u7B56\u3002</p><p><strong>Dynamic Systems Development Method (DSDM). \u52A8\u6001\u7CFB\u7EDF\u5F00\u53D1\u65B9\u6CD5</strong> \u4E00\u79CD\u654F\u6377\u9879\u76EE\u4EA4\u4ED8\u6846\u67B6\u3002</p><p><strong>Evolutionary Value Delivery (Evo). \u6E10\u8FDB\u4EF7\u503C\u4EA4\u4ED8</strong> \u516C\u8BA4\u7684\u9996\u8981\u654F\u6377\u65B9\u6CD5\uFF0C\u62E5\u6709\u5176\u4ED6\u65B9\u6CD5\u6240\u4E0D\u5177\u5907\u7684\u7279\u70B9\uFF0C\u91CD\u70B9\u5173\u6CE8\u5411\u76F8\u5173\u65B9\u4EA4\u4ED8\u591A\u79CD\u53EF\u8861\u91CF\u7684\u4EF7\u503C\u9700\u6C42\u3002</p><p><strong>eXtreme Programming. \u6781\u9650\u7F16\u7A0B</strong> \u4E00\u79CD\u654F\u6377\u8F6F\u4EF6\u5F00\u53D1\u65B9\u6CD5\uFF0C\u4E0D\u4EC5\u80FD\u63D0\u9AD8\u8F6F\u4EF6\u8D28\u91CF\u3001\u6539\u5584\u8F6F\u4EF6\u5BF9\u4E0D\u65AD\u53D8\u5316\u7684\u5BA2\u6237\u9700\u6C42\u7684\u54CD\u5E94\u80FD\u529B\uFF0C\u8FD8\u80FD\u7F29\u77ED\u8F6F\u4EF6\u7248\u672C\u53D1\u5E03\u5468\u671F\uFF0C\u589E\u52A0\u53D1\u5E03\u9891\u7387\u3002</p><p><strong>Feature-Driven Development. \u529F\u80FD\u9A71\u52A8\u5F00\u53D1</strong> \u4ECE\u5BA2\u6237\u91CD\u89C6\u7684\u529F\u80FD\u89D2\u5EA6\u89E6\u53D1\u7684\u8F7B\u91CF\u7EA7\u654F\u6377\u8F6F\u4EF6\u5F00\u53D1\u65B9\u6CD5\u3002</p><p><strong>Fit for Purpose. \u7B26\u5408\u76EE\u7684</strong> \u7B26\u5408\u9884\u671F\u76EE\u7684\u7684\u4EA7\u54C1\u3002</p><p><strong>Fit for Use. \u9002\u5408\u4F7F\u7528</strong> \u4EE5\u5F53\u524D\u5F62\u52BF\u4F7F\u7528\u80FD\u5B9E\u73B0\u5176\u9884\u671F\u76EE\u7684\u7684\u4EA7\u54C1\u3002</p><p><strong>Flow Master. \u5DE5\u4F5C\u6D41\u4E3B\u7BA1</strong> \u5728\u8FDE\u7EED\u5DE5\u4F5C\u6D41\u6216\u770B\u677F\u73AF\u5883\u4E0B\u5DE5\u4F5C\u7684\u56E2\u961F\u6559\u7EC3\u548C\u670D\u52A1\u8BF7\u6C42\u7BA1\u7406\u8005\u3002\u76F8\u5F53\u4E8E Scrum \u4E3B\u7BA1\u3002</p><p><strong>Framework. \u6846\u67B6</strong> \u6BD4\u67D0\u79CD\u7279\u5B9A\u65B9\u6CD5\u66F4\u4E3A\u901A\u7528\u7684\u65B9\u6CD5\u3002</p><p><strong>Functional Requirement. \u529F\u80FD\u9700\u6C42</strong> \u6307\u67D0\u4EA7\u54C1\u6216\u670D\u52A1\u5E94\u5B8C\u6210\u7684\u4E00\u4E2A\u7279\u5B9A\u884C\u4E3A\u3002</p><p><strong>Functional Specification. \u529F\u80FD\u89C4\u8303</strong> \u6307\u67D0\u7CFB\u7EDF\u6216\u5E94\u7528\u9700\u8981\u5B9E\u73B0\u7684\u4E00\u79CD\u7279\u5B9A\u529F\u80FD\u3002\u5B83\u901A\u5E38\u4F53\u73B0\u5728\u529F\u80FD\u89C4\u8303\u6587\u6863\u4E2D\u3002</p><p><strong>Hoshin Kanri.\u65B9\u9488\u7BA1\u7406</strong> \u4E00\u79CD\u7B56\u7565\u6216\u653F\u7B56\u7684\u90E8\u7F72\u65B9\u6CD5\u3002</p><p><strong>Hybrid Approach. \u6DF7\u5408\u65B9\u6CD5</strong> \u6307\u4E24\u79CD\u6216\u4E24\u79CD\u4EE5\u5546\u654F\u6377\u6216\u975E\u654F\u6377\u8981\u7D20\u7684\u7EC4\u5408\uFF0C\u636E\u6709\u975E\u654F\u6377\u7684\u6700\u7EC8\u7ED3\u679C\u3002</p><p><strong>IDEAL. IDEAL</strong> \u4E00\u79CD\u7EC4\u7EC7\u6539\u8FDB\u6A21\u578B\uFF0C\u4EE5\u6240\u63CF\u8FF0\u7684\u4E94\u4E2A\u9636\u6BB5\u547D\u540D\u542F\u52A8\u3001\u8BCA\u65AD\u3001\u786E\u7ACB\u3001\u6267\u884C\u548C\u5B66\u4E60\u3002</p><p><strong>Impact Mapping. \u5F71\u54CD\u5730\u56FE</strong> \u6218\u7565\u89C4\u5212\u6280\u672F\uFF0C\u88AB\u7EC4\u7EC7\u4F5C\u4E3A\u6253\u9020\u65B0\u4EA7\u54C1\u7684\u8DEF\u7EBF\u56FE\u3002</p><p><strong>Impediment. \u969C\u788D</strong> \u6307\u59A8\u788D\u56E2\u961F\u8FBE\u6210\u5176\u76EE\u6807\u7684\u5E72\u6270\u56E0\u7D20\u3002\u4E5F\u6210\u4E3A\u963B\u788D\u3002</p><p><strong>Increment. \u589E\u91CF</strong> \u7ECF\u8FC7\u6D4B\u8BD5\u3001\u9A8C\u6536\u7684\u4F7F\u7528\u53EF\u4EA4\u4ED8\u6210\u679C\u4E5F\u662F\u9879\u76EE\u603B\u4F53\u6210\u679C\u7684\u7EC4\u6210\u90E8\u5206\u3002</p><p><strong>Incremental Life Cycle. \u589E\u91CF\u578B\u751F\u547D\u5468\u671F</strong> \u63D0\u4F9B\u5DF2\u5B8C\u5DE5\u7684\u3001\u5BA2\u6237\u53EF\u7ACB\u5373\u4F7F\u7528\u7684\u53EF\u4EA4\u4ED8\u6210\u679C\u7684\u65B9\u6CD5\u3002</p><p><strong>Information Radiator. \u4FE1\u606F\u53D1\u5C04\u6E90</strong> \u53EF\u89C1 \u7684\u5B9E\u7269\u5C55\u793A\uFF0C\u5411\u7EC4\u7EC7\u5185\u5176\u4ED6\u6210\u5458\u63D0\u4F9B\u4FE1\u606F\uFF0C\u5728\u4E0D\u5E72\u6270\u56E2\u961F\u7684\u60C5\u51B5\u4E0B\u5373\u65F6\u5B9E\u73B0\u77E5\u8BC6\u5171\u4EAB\u3002</p><p><strong>I-shaped. I \u578B\u4EBA\u624D</strong> \u6307\u6DF1\u5165\u638C\u63E1\u5355\u4E00\u4E13\u4E1A\u6280\u80FD\u7684\u4EBA\u5458\uFF0C\u4ED6\u4EEC\u4E0D\u5177\u5907\u56E2\u961F\u6240\u9700\u7684\u5176\u4ED6\u6280\u80FD\u6216\u5BF9\u5176\u4E0D\u611F\u5174\u8DA3\u3002</p><p><strong>Iteration. \u8FED\u4EE3</strong> \u4EA7\u54C1\u6216\u53EF\u4EA4\u4ED8\u6210\u679C\u5F00\u53D1\u7684\u4E00\u4E2A\u65F6\u95F4\u76D2\uFF0C\u5FAA\u73AF\u5176\u4E2D\u9700\u8981\u6267\u884C\u4EA4\u4ED8\u4EF7\u503C\u6240\u9700\u7684\u6240\u6709\u5DE5\u4F5C\u3002</p><p><strong>Iterative Life Cycle. \u8FED\u4EE3\u578B\u751F\u547D\u5468\u671F</strong> \u5141\u8BB8\u5BF9\u672A\u5B8C\u6210\u5DE5\u4F5C\u63D0\u4F9B\u53CD\u9988\u4ECE\u800C\u5BF9\u5DE5\u4F5C\u52A0\u4EE5\u6539\u5584\u548C\u4FEE\u6539\u7684\u7684\u65B9\u6CD5\u3002</p><p><strong>Kaizen Events. \u6539\u5584\u6D3B\u52A8</strong> \u65E8\u5728\u5BF9\u7CFB\u7EDF\u52A0\u4EE5\u6539\u5584\u7684\u6D3B\u52A8\u3002</p><p><strong>Kanban Board. \u770B\u677F\u9762\u677F</strong> \u53EF\u89C6\u8BDD\u5DE5\u5177\uFF0C\u80FD\u591F\u901A\u8FC7\u74F6\u9888\u548C\u5DE5\u4F5C\u91CF\u7684\u6709\u5F62\u5448\u73B0\u6539\u5584\u5DE5\u4F5C\u6D41\u3002</p><p><strong>Kanban Method. \u770B\u677F\u65B9\u6CD5</strong> \u53D7\u5230\u770B\u677F\u5E93\u5B58\u63A7\u5236\u7CFB\u7EDF\u542F\u53D1\u7684\u654F\u6377\u65B9\u6CD5\uFF0C\u4E13\u95E8\u7528\u4E8E\u77E5\u8BC6\u5DE5\u4F5C\u3002</p><p><strong>Large-Scale Scrum (LeSS). \u5927\u89C4\u6A21\u654F\u6377\u5F00\u53D1</strong> \u4E00\u79CD\u4EA7\u54C1\u5F00\u53D1\u6846\u67B6\uFF0C\u5B83\u6839\u636E\u6269\u5C55\u6307\u5BFC\u65B9\u9488\u5E93\u8FBE\u654F\u6377\u5F00\u53D1\u89C4\u6A21\uFF0C\u540C\u65F6\u4FDD\u7559\u539F\u6709\u7684\u654F\u6377\u5F00\u53D1\u76EE\u7684\u3002</p><p><strong>Lean Software Development (LSD). \u7CBE\u76CA\u8F6F\u4EF6\u5F00\u53D1</strong> \u8F6F\u4EF6\u5F00\u53D1\u9886\u57DF\u7684\u7CBE\u76CA\u5236\u9020\u539F\u7406\u548C\u5B9E\u8DF5\uFF0C\u5B83\u57FA\u4E8E\u4E00\u5957\u65E8\u5728\u6EE1\u8DB3\u8D28\u91CF\u3001\u901F\u5EA6\u548C\u5BA2\u6237\u5B9A\u4F4D\u8981\u6C42\u7684\u539F\u7406\u548C\u5B9E\u8DF5\u3002</p><p><strong>Life Cycle. \u751F\u547D\u5468\u671F</strong> \u6307\u4EA7\u54C1\u4ECE\u6784\u60F3\u3001\u521B\u9020\u5230\u6295\u5165\u4F7F\u7528\u7684\u8FC7\u7A0B\u3002</p><p><strong>Mobbing. \u7FA4\u4F53\u5F00\u53D1</strong> \u4E00\u79CD\u5DE5\u4F5C\u6280\u672F\uFF0C\u5176\u4E2D\u591A\u540D\u56E2\u961F\u6210\u5458\u56F4\u7ED5\u67D0\u4E2A\u5177\u4F53\u5DE5\u4F5C\u9879\u76EE\u540C\u65F6\u534F\u8C03\u5DE5\u4F5C\u3002</p><p><strong>Organizational Bias. \u7EC4\u7EC7\u504F\u597D</strong> \u7EC4\u7EC7\u5BF9\u4E00\u7EC4\u8861\u91CF\u6307\u6807\u7684\u9009\u62E9\u3002\u8FD9\u7EC4\u8861\u91CF\u6307\u6807\u5177\u6709\u5982\u4E0B\u6838\u5FC3\uFF0C\u4EF7\u503C\u63A2\u7D22\u4E0E\u6267\u884C\u3001\u901F\u5EA6\u4E0E\u7A33\u5B9A\u6027\u3001\u6570\u91CF\u4E0E\u8D28\u91CF\u3001\u7075\u6D3B\u6027\u4E0E\u53EF\u9884\u6D4B\u6027\u3002</p><p><strong>Organizational Change Management. \u7EC4\u7EC7\u53D8\u9769\u7BA1\u7406</strong> \u5168\u9762\u7684\u3001\u5468\u671F\u6027\u7684\u3001\u7ED3\u6784\u5316\u65B9\u6CD5\uFF0C\u65E8\u5728\u4F7F\u4E2A\u4EBA\u3001\u7FA4\u7EC4\u548C\u7EC4\u7EC7\u5728\u4ECE\u5F53\u524D\u72B6\u6001\u8F6C\u6362\u672A\u672A\u6765\u72B6\u6001\u65F6\u5B9E\u73B0\u9884\u671F\u7684\u4E1A\u52A1\u53D7\u76CA\u3002</p><p><strong>Paint-Drip. \u201D\u989C\u6599\u6EF4\u6D12\u201C\u4EBA\u624D</strong></p><p><strong>Pairing. \u7ED3\u5BF9</strong> \u7ED3\u5BF9\u5DE5\u4F5C\u3002</p><p><strong>Pair Programming. \u7ED3\u5BF9\u7F16\u7A0B</strong></p><p><strong>Pair Work. \u7ED3\u5BF9\u5DE5\u4F5C</strong> \u7531\u4E24\u540D\u56E2\u961F\u6210\u5458\u7ED3\u5BF9\u3001\u540C\u65F6\u4ECE\u4E8B\u540C\u4E00\u5DE5\u4F5C\u9879\u76EE\u7684\u6280\u672F\u3002</p><p><strong>Personas. \u4EBA\u7269\u89D2\u8272</strong> \u4EE3\u8868\u4E00\u7EC4\u7C7B\u4F3C\u7EC8\u7AEF\u7528\u6237\u7684\u5178\u578B\u7528\u6237\uFF0C\u901A\u8FC7\u5176\u76EE\u6807\u3001\u52A8\u673A\u548C\u636E\u6709\u4EE3\u8868\u6027\u7684\u4E2A\u4EBA\u7279\u5F81\u63CF\u8FF0\u3002</p><p><strong>Pivot. \u8F6C\u5411</strong> \u6307\u8BA1\u5212\u4E2D\u7684\u65B9\u5411\u4FEE\u6B63\u65E8\u5728\u68C0\u6D4B\u4EA7\u54C1\u6216\u518C\u7F57\u7684\u65B0\u5047\u8BBE\u3002</p><p><strong>Plan-Do-Check-Act(PDCA). \u8BA1\u5212-\u6267\u884C-\u68C0\u67E5-\u884C\u52A8</strong> \u7EC4\u7EC7\u4E2D\u7684\u4E00\u79CD\u8FED\u4EE3\u7BA1\u7406\u65B9\u6CD5\u65E8\u5728\u4FC3\u8FDB\u8FC7\u7A0B\u548C\u4EA7\u54C1\u7684\u63A7\u5236\u548C\u6301\u7EED\u6539\u5584\u3002</p><p><strong>Plan-Driven Approach. \u8BA1\u5212\u9A71\u52A8\u65B9\u6CD5</strong> \u53C2\u8003\u9884\u6D4B\u6CD5\u3002</p><p><strong>Predictive Approach. \u9884\u6D4B\u6CD5</strong> \u4E00\u79CD\u5DE5\u4F5C\u7BA1\u7406\u65B9\u6CD5\u5728\u6574\u4E2A\u9879\u76EE\u751F\u547D\u5468\u671F\u4E2D\u5E94\u7528\u5DE5\u4F5C\u8BA1\u5212\u548C\u7BA1\u7406\u5DE5\u4F5C\u8BA1\u5212\u3002</p><p><strong>Predictive Life Cycle. \u9884\u6D4B\u578B\u751F\u547D\u5468\u671F</strong> \u4E00\u79CD\u66F4\u4E3A\u4F20\u7EDF\u7684\u65B9\u6CD5\uFF0C\u5927\u90E8\u5206\u89C4\u5212\u5728\u524D\u671F\u8FDB\u884C\u968F\u540E\u4E00\u6B21\u6027\u6267\u884C\u5B83\u662F\u4E00\u4E2A\u8FDE\u7EED\u7684\u8FC7\u7A0B\u3002</p><p><strong>Project Management Office (PMO). \u9879\u76EE\u7BA1\u7406\u529E\u516C\u5BA4</strong> \u4E0E\u9879\u76EE\u76F8\u5173\u7684\u6CBB\u7406\u8FC7\u7A0B\u8FDB\u884C\u6807\u51C6\u5316\u5E76\u4FC3\u8FDB\u8D44\u6E90\u3001\u65B9\u6CD5\u8BBA\u3001\u5DE5\u5177\u548C\u6280\u672F\u5171\u4EAB\u7684\u4E00\u79CD\u7BA1\u7406\u67B6\u6784\u3002</p><p><strong>Product Backlog. \u4EA7\u54C1\u5F85\u529E\u4E8B\u9879\u5217\u8868</strong> \u6307\u56E2\u961F\u56F4\u7ED5\u67D0\u4EA7\u54C1\u7EF4\u62A4\u7684\u4E00\u4E2A\u4EE5\u7528\u6237\u672A\u4E2D\u5FC3\u7684\u9700\u6C42\u7684\u6709\u5E8F\u5217\u8868\u3002</p><p><strong>Product Owner. \u4EA7\u54C1\u8D1F\u8D23\u4EBA</strong> \u8D1F\u8D23\u4F7F\u4EA7\u54C1\u5B9E\u73B0\u6700\u5927\u4EF7\u503C\u7684\u4EBA\u5458\uFF0C\u5176\u5BF9\u6240\u521B\u5EFA\u7684\u7EC8\u7AEF\u4EA7\u54C1\u8D1F\u8D23\u5E76\u627F\u62C5\u6700\u7EC8\u8D23\u4EFB\u3002\u53E6\u53C2\u89C1\u670D\u52A1\u8BF7\u6C42\u7BA1\u7406\u8005\u3002</p><p><strong>Progressive Elaboration. \u6E10\u8FDB\u660E\u7EC6</strong> \u968F\u7740\u4FE1\u606F\u8D8A\u6765\u8D8A\u591A\u3001\u4F30\u7B97\u8D8A\u6765\u8D8A\u51C6\u786E\uFF0C\u8FDB\u800C\u4E0D\u65AD\u63D0\u9AD8\u9879\u76EE\u7BA1\u7406\u8BA1\u5212\u7684\u8BE6\u7EC6\u7A0B\u5EA6\u7684\u8FED\u4EE3\u8FC7\u7A0B\u3002</p><p><strong>Refactoring. \u91CD\u6784</strong> \u4E00\u79CD\u4EA7\u54C1\u8D28\u91CF\u6280\u672F\uFF0C\u5176\u901A\u8FC7\u63D0\u9AD8\u4EA7\u54C1\u7684\u53EF\u7EF4\u62A4\u6027\u548C\u5176\u4ED6\u9700\u8981\u7684\u5C5E\u6027\u6765\u6539\u5584\u4EA7\u54C1\u8BBE\u8BA1\uFF0C\u540C\u65F6\u5E76\u4E0D\u6539\u53D8\u4EA7\u54C1\u7684\u9884\u671F\u884C\u4E3A\u3002</p><p><strong>Retrospective. \u56DE\u987E</strong> \u4E00\u79CD\u5B9A\u671F\u8FDB\u884C\u7684\u7814\u8BA8\u6D3B\u52A8\u3002\u5176\u4E2D\u53C2\u4E0E\u8005\u9488\u5BF9\u5176\u5DE5\u4F5C\u548C\u5DE5\u4F5C\u6210\u679C\u8FDB\u884C\u63A2\u8BA8\uFF0C\u65E8\u5728\u5BF9\u8FC7\u7A0B\u548C\u4EA7\u54C1\u505A\u51FA\u6539\u8FDB\u3002</p><p><strong>Rolling Wave Planning. \u6EDA\u52A8\u5F0F\u89C4\u5212</strong> \u4E00\u79CD\u8FED\u4EE3\u5F0F\u7684\u89C4\u5212\u6280\u672F\uFF0C\u5BF9\u8FD1\u671F\u8981\u5B8C\u6210\u7684\u5DE5\u4F5C\u8FDB\u884C\u8BE6\u7EC6\u89C4\u5212\uFF0C\u5BF9\u8FDC\u671F\u5DE5\u4F5C\u53EA\u505A\u7C97\u7565\u89C4\u5212\u3002</p><p><strong>Scaled Agile Framework (SAFe). \u5927\u89C4\u6A21\u654F\u6377\u6846\u67B6</strong> \u4E00\u4E2A\u96C6\u6210\u6A21\u5F0F\u7684\u77E5\u8BC6\u5E93\uFF0C\u7528\u4E8E\u4F01\u4E1A\u8303\u56F4\u7684\u7CBE\u76CA\u5F00\u53D1\u3002</p><p><strong>Scrum. Scrum</strong> \u4E00\u79CD\u590D\u6742\u4EA7\u54C1\u5F00\u53D1\u4E0E\u7EF4\u6301\u7684\u654F\u6377\u6846\u67B6\uFF0C\u5B83\u7531\u7279\u5B9A\u7684\u89D2\u8272\u3001\u4E8B\u4EF6\u548C\u5DE5\u4EF6\u7B49\u5143\u7D20\u7EC4\u6210\u3002</p><p><strong>Scrumban. Scrumban</strong> \u4E00\u79CD\u5728\u56E2\u961F\u9009\u62E9 Scrum \u4F5C\u4E3A\u5DE5\u4F5C\u65B9\u5F0F\u65F6\u4EA7\u751F\u7684\u7BA1\u7406\u6846\u67B6\uFF0C\u5B83\u4EE5\u770B\u677F\u65B9\u6CD5\u4F5C\u4E3A\u900F\u89C6\u955C\u4ECE\u800C\u5BA1\u89C6\u3001\u7406\u89E3\u5E76\u6301\u7EED\u6539\u5584\u5176\u5DE5\u4F5C\u3002</p><p><strong>Scrum Board. Scrum \u677F</strong> \u4E00\u79CD\u7528\u4E8E\u7BA1\u7406\u4EA7\u54C1\u5F85\u529E\u4E8B\u9879\u5217\u8868\u548C\u51B2\u523A\u5F85\u529E\u4E8B\u9879\u5217\u8868\u7684\u4FE1\u606F\u53D1\u5C04\u6E90\uFF0C\u5B83\u80FD\u663E\u793A\u5DE5\u4F5C\u6D41\u53CA\u5176\u74F6\u9888\u3002</p><p><strong>Scrum Master. Scrum \u4E3B\u7BA1</strong> \u6307\u5F00\u53D1\u56E2\u961F\u7684\u6559\u7EC3\u548C Scrum \u6846\u67B6\u4E2D\u7684\u4EA7\u54C1\u8D1F\u8D23\u4EBA\u3002\u5176\u8D1F\u8D23\u6D88\u9664\u969C\u788D\u4FC3\u8FDB\u5BCC\u6709\u6210\u6548\u7684\u4E8B\u4EF6\u5E76\u4FDD\u62A4\u56E2\u961F\u514D\u53D7\u5E72\u6270\u3002</p><p><strong>Scrum Team. Scrum \u56E2\u961F</strong> \u6307\u5728\u654F\u6377\u5F00\u53D1\u4E2D\u5F00\u53D1\u56E2\u961F\u3001Scrum \u4E3B\u7BA1\u548C\u4EA7\u54C1\u8D1F\u8D23\u4EBA\u7684\u603B\u548C\u3002</p><p><strong>Self-Organizing Team. \u81EA\u7EC4\u7EC7\u56E2\u961F</strong> \u4E00\u79CD\u8DE8\u804C\u80FD\u56E2\u961F\uFF0C\u5176\u4E2D\u4E3A\u5B9E\u73B0\u56E2\u961F\u76EE\u6807\u56E2\u961F\u6210\u5458\u6839\u636E\u9700\u8981\u8F6E\u6362\u7740\u53D1\u6325\u9886\u5BFC\u4F5C\u7528\u3002</p><p><strong>Servant Leadership. \u670D\u52A1\u578B\u9886\u5BFC</strong> \u4E00\u79CD\u50CF\u56E2\u961F\u63D0\u4F9B\u670D\u52A1\u7684\u9886\u5BFC\uFF0C\u5B9E\u8DF5\u91CD\u70B9\u662F\u7406\u89E3\u5E76\u89E3\u51B3\u56E2\u961F\u6210\u5458\u7684\u9700\u6C42\u548C\u53D1\u5C55\uFF0C\u5C3D\u53EF\u80FD\u63D0\u9AD8\u56E2\u961F\u7684\u7EE9\u6548\u3002</p><p><strong>Service Request Manager. \u670D\u52A1\u8BF7\u6C42\u7BA1\u7406\u8005</strong> \u6307\u5728\u8FDE\u7EED\u5DE5\u4F5C\u6D41\u6216\u770B\u677F\u73AF\u5883\u4E2D\u8D1F\u8D23\u6574\u7406\u670D\u52A1\u8BF7\u6C42\uFF0C\u65E8\u5728\u5B9E\u73B0\u6700\u5927\u4EF7\u503C\u7684\u4EBA\u5458\u3002\u5B83\u76F8\u5F53\u4E8E\u4EA7\u54C1\u8D1F\u8D23\u4EBA\u3002</p><p><strong>Siloed Organization. \u5B64\u5C9B\u7EC4\u7EC7</strong> \u53EA\u80FD\u90E8\u5206\u6EE1\u8DB3\u5411\u5BA2\u6237\u4EA4\u4ED8\u4EF7\u503C\u7684\u9700\u6C42\u7684\u65B9\u5F0F\u6784\u5EFA\u7684\u7EC4\u7EC7\u3002\u53C2\u7167\u4EF7\u503C\u6D41\u3002</p><p><strong>Single Loop Learning. \u5355\u5FAA\u73AF\u5B66\u4E60</strong> \u6307\u672A\u6839\u636E\u7ECF\u9A8C\u63D0\u51FA\u8D28\u7591\u3001\u4EC5\u4EC5\u5229\u7528\u9884\u5148\u786E\u5B9A\u7684\u7279\u5B9A\u65B9\u6CD5\u89E3\u51B3\u95EE\u9898\u7684\u5B9E\u8DF5\u3002</p><p><strong>Smoke Testing. \u5192\u70DF\u6D4B\u8BD5</strong> \u5229\u7528\u4E00\u7EC4\u8F7B\u91CF\u7EA7\u6D4B\u8BD5\uFF0C\u786E\u4FDD\u6B63\u5728\u5F00\u53D1\u7684\u7CFB\u7EDF\u5B9E\u73B0\u6700\u91CD\u8981\u7684\u9884\u671F\u529F\u80FD\u7684\u5B9E\u8DF5\u3002</p><p><strong>Specification by Example (SBE). \u5B9E\u4F8B\u5316\u9700\u6C42</strong> \u4E3A\u8F6F\u4EF6\u4EA7\u54C1\u5B9A\u4E49\u9700\u6C42\u548C\u5B9A\u4E49\u9762\u5411\u5546\u4E1A\u7684\u529F\u80FD\u6D4B\u8BD5\u7684\u4E00\u79CD\u534F\u4F5C\u65B9\u6CD5\uFF0C\u57FA\u4E8E\u4F7F\u7528\u5B9E\u4F8B\u83B7\u53D6\u5E76\u9610\u660E\u9700\u6C42\u800C\u4E0D\u662F\u62BD\u8C61\u9648\u8FF0\u9700\u6C42\u3002</p><p><strong>Spike. \u523A\u63A2</strong> \u6307\u9879\u76EE\u4E2D\u77ED\u6682\u7684\u65F6\u95F4\u95F4\u9694\uFF0C\u901A\u5E38\u957F\u5EA6\u56FA\u5B9A\u5728\u6B64\u671F\u95F4\uFF0C\u56E2\u961F\u5F00\u5C55\u7814\u7A76\u6216\u9488\u5BF9\u65B9\u6848\u7684\u67D0\u4E2A\u65B9\u9762\u8FDB\u884C\u539F\u578B\u7814\u7A76\u9A8C\u8BC1\u5176\u53EF\u80FD\u6027\u3002</p><p><strong>Sprint. \u51B2\u523A</strong> \u63CF\u8FF0\u654F\u6377\u8003\u6CD5\u4E2D\u7684\u65F6\u95F4\u76D2\u8FED\u4EE3\u3002</p><p><strong>Sprint Backlog. \u51B2\u523A\u5F85\u529E\u4E8B\u9879\u5217\u8868</strong> \u6307\u7531 Scrum \u56E2\u961F\u8BC6\u522B\u7684\u3001\u9700\u8981\u5728 Sprint \u4E2D\u5B8C\u6210\u7684\u5DE5\u4F5C\u4E8B\u9879\u5217\u8868\u3002</p><p><strong>Sprint Planning. \u51B2\u523A\u8BA1\u5212</strong> \u6307\u654F\u6377\u8003\u6CD5\u4E2D\u7684\u4E00\u4E2A\u534F\u4F5C\u4E8B\u4EF6\uFF0C\u56E2\u961F\u4E3A\u76EE\u524D\u7684\u51B2\u523A\u5236\u5B9A\u5DE5\u4F5C\u8BA1\u5212\u3002</p><p><strong>Story Point. \u6545\u4E8B\u70B9</strong> \u7528\u4E8E\u76F8\u5173\u7528\u6237\u6545\u4E8B\u4F30\u7B97\u6280\u672F\u4E2D\u7684\u4E00\u79CD\u65E0\u91CF\u7EB2\u6307\u6807\u3002</p><p><strong>Swarming. \u7FA4\u96C6</strong> \u6307\u4E00\u79CD\u56E2\u961F\u591A\u4E2A\u6210\u5458\u5408\u4F5C\u3001\u91CD\u70B9\u6D88\u9664\u7279\u5B9A\u969C\u788D\u7684\u6280\u672F\u3002</p><p><strong>Technical Debt. \u6280\u672F\u503A\u52A1</strong> \u6307\u4EA7\u54C1\u751F\u547D\u5468\u671F\u65E9\u671F\u672A\u80FD\u5B8C\u6210\u5DE5\u4F5C\u7684\u9012\u5EF6\u6210\u672C\u3002</p><p><strong>Test-Driven Development. \u6D4B\u8BD5\u9A71\u52A8\u5F00\u53D1</strong> \u5728\u5DE5\u4F5C\u5F00\u59CB\u524D\u5B9A\u4E49\u6D4B\u8BD5\u7684\u4E00\u79CD\u6280\u672F\uFF0C\u5B83\u91C7\u7528\u96F6\u7F3A\u9677\u7684\u601D\u7EF4\u6A21\u5F0F\u4F7F\u5DE5\u4F5C\u8FDB\u5EA6\u80FD\u6301\u7EED\u5F97\u5230\u786E\u8BA4\u3002</p><p><strong>Timebox. \u65F6\u95F4\u76D2</strong> \u6307\u4E00\u6BB5\u56FA\u5B9A\u65F6\u95F4\u4F8B\u5982 1 \u5468\u3002</p><p><strong>T-shaped. T \u578B\u4EBA\u624D</strong> \u6307\u6DF1\u5165\u638C\u63E1\u5355\u4E00\u4E13\u4E1A\u6280\u80FD\uFF0C\u5E76\u5E7F\u6CDB\u638C\u63E1\u56E2\u961F\u6240\u9700\u5176\u4ED6\u6280\u80FD\u7684\u4EBA\u5458\u3002</p><p><strong>User Story. \u7528\u6237\u6545\u4E8B</strong> \u9488\u5BF9\u7279\u5B9A\u7528\u6237\u7684\u53EF\u4EA4\u4ED8\u6210\u679C\u4EF7\u503C\u7684\u7B80\u8981\u63CF\u8FF0\u3002\u662F\u5BF9\u6F84\u6E05\u7EC6\u8282\u5BF9\u8BDD\u7684\u627F\u8BFA\u3002</p><p><strong>User Story Mapping. \u7528\u6237\u6545\u4E8B\u5730\u56FE</strong> \u4E00\u5B97\u5C06\u5DE5\u4F5C\u7EB3\u5165\u4E00\u4E2A\u5E94\u7528\u6A21\u578B\u7684\u53EF\u89C6\u5316\u5B9E\u8DF5\uFF0C\u65E8\u5728\u5E2E\u52A9\u7406\u89E3\u968F\u7740\u65F6\u95F4\u63A8\u79FB\u800C\u521B\u5EFA\u7684\u9AD8\u4EF7\u503C\u529F\u80FD\u96C6\uFF0C\u53D1\u73B0\u5F85\u529E\u4E8B\u9879\u5217\u8868\u4E2D\u7684\u9057\u6F0F\uFF0C\u6709\u6548\u89C4\u5212\u5411\u7528\u6237\u4EA4\u4ED8\u4EF7\u503C\u7684\u8F6F\u4EF6\u53D1\u5E03\u3002</p><p><strong>UX Design. \u7528\u6237\u4F53\u9A8C\u8BBE\u8BA1</strong> \u4E00\u79CD\u4FC3\u8FDB\u7528\u6237\u4F53\u9A8C\u7684\u8FC7\u7A0B\uFF0C\u91CD\u70B9\u6539\u5584\u7528\u6237\u4E0E\u4EA7\u54C1\u4E92\u52A8\u4E2D\u7684\u53EF\u7528\u6027\u548C\u53EF\u8BBF\u95EE\u6027\u3002</p><p><strong>Value Stream. \u4EF7\u503C\u6D41</strong> \u4E00\u79CD\u7EC4\u7EC7\u6027\u7ED3\u6784\uFF0C\u91CD\u70B9\u5173\u6CE8\u901A\u8FC7\u7279\u5B9A\u4EA7\u54C1\u6216\u670D\u52A1\u4EA4\u4ED8\u6D41\u5411\u5BA2\u6237\u7684\u4EF7\u503C\u3002</p><p><strong>Value Stream Mapping. \u4EF7\u503C\u6D41\u56FE</strong> \u7528\u4E8E\u8BB0\u5F55\u3001\u5206\u6790\u548C\u6539\u5584\u4E3A\u5BA2\u6237\u751F\u4EA7\u4EA7\u54C1\u6216\u63D0\u4F9B\u670D\u52A1\u65F6\u6240\u9700\u7684\u4FE1\u606F\u6216\u6750\u6599\u6D41\u7684\u7CBE\u76CA\u4F01\u4E1A\u6280\u672F\u3002</p>',114);function s(p,g){return o}var a=t(n,[["render",s],["__file","appendix3.html.vue"]]);export{a as default};
